refsection.programlisting:
--If you have a table of polygons SELECT gid, ST_ExteriorRing(geom) AS ering FROM sometable;
--If you have a table of MULTIPOLYGONs --and want to return a MULTILINESTRING composed of the exterior rings of each polygon SELECT gid, ST_Collect(ST_ExteriorRing(geom)) AS erings FROM (SELECT gid, (ST_Dump(geom)).geom As geom FROM sometable) As foo GROUP BY gid;
--3d Example SELECT ST_AsEWKT( ST_ExteriorRing( ST_GeomFromEWKT('POLYGON((0 0 1, 1 1 1, 1 2 1, 1 1 1, 0 0 1))') ) );
st_asewkt --------- LINESTRING(0 0 1,1 1 1,1 2 1,1 1 1,0 0 1)
